"use strict";(self.webpackChunkdocusaur_1=self.webpackChunkdocusaur_1||[]).push([[5278],{28453:(e,t,n)=>{n.d(t,{R:()=>a,x:()=>u});var s=n(96540);const i={},r=s.createContext(i);function a(e){const t=s.useContext(r);return s.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function u(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(r.Provider,{value:t},e.children)}},73943:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>o,contentTitle:()=>u,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"L7/0/intro","title":"Introduction : art, travail et technique","description":"\u201cArs\u201d et \u201cTekhn\xe8\u201d : un m\xeame mot pour l\u2019art et la technique","source":"@site/docs/L7/0/intro.md","sourceDirName":"L7/0","slug":"/L7/0/intro","permalink":"/docs/L7/0/intro","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"sidebar_position":1,"id":"intro"},"sidebar":"tutorialSidebar","previous":{"title":"Textes de la le\xe7on","permalink":"/docs/L7/textes"},"next":{"title":"1. L\u2019art, du travail ou de l\u2019inspiration ?","permalink":"/docs/L7/1/"}}');var i=n(74848),r=n(28453);const a={sidebar_position:1,id:"intro"},u="Introduction : art, travail et technique",o={},l=[{value:"\u201cArs\u201d et \u201cTekhn\xe8\u201d : un m\xeame mot pour l\u2019art et la technique",id:"ars-et-tekhn\xe8--un-m\xeame-mot-pour-lart-et-la-technique",level:2},{value:"Trois \xe9l\xe9ments classiques de distinction entre ce qui est de l\u2019art et ce qui n\u2019en est pas",id:"trois-\xe9l\xe9ments-classiques-de-distinction-entre-ce-qui-est-de-lart-et-ce-qui-nen-est-pas",level:2}];function d(e){const t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"introduction--art-travail-et-technique",children:"Introduction : art, travail et technique"})}),"\n",(0,i.jsx)(t.h2,{id:"ars-et-tekhn\xe8--un-m\xeame-mot-pour-lart-et-la-technique",children:"\u201cArs\u201d et \u201cTekhn\xe8\u201d : un m\xeame mot pour l\u2019art et la technique"}),"\n",(0,i.jsx)(t.p,{children:"Beaux-arts, techniques de chant, arts martiaux, techniques de combat, l\u2019art et la mani\xe8re, un art de vivre, les r\xe8gles de l\u2019art, l\u2019art de la guerre, etc.\nCes expressions montrent l\u2019origine commune des mots art et technique : ars (latin) et tekhne (grec) signifient \u201csavoir-faire\u201d (\xe0 l\u2019origine des productions humaines, en opposition aux cr\xe9ations de la nature). Nous retrouvons cette racine commune ars dans artiste et artisan. Avant l\u2019\xe9poque des Lumi\xe8res, l\u2019art ne se distingue pas fondamentalement de la technique. Au moyen-\xe2ge, la hi\xe9rarchie se fait entre \u201carts lib\xe9raux\u201d (disciplines intellectuelles) et \u201carts m\xe9caniques\u201d (disciplines manuelles), et les peintres, consid\xe9r\xe9s comme des artisans, sont assimil\xe9s \xe0 la seconde cat\xe9gorie. L\xe9onard de Vinci a tent\xe9 en vain d\u2019\xeatre rattach\xe9 aux arts lib\xe9raux.\nCe n\u2019est qu\u2019avec l\u2019apparition de la cat\xe9gorie des \u201cbeaux-arts\u201d (terme apparu dans L\u2019Encyclop\xe9die de Diderot et d\u2019Alembert en 1752) que les artistes s\u2019\xe9vadent du domaine des \u201cArts et M\xe9tiers\u201d. Cela a concern\xe9 d\u2019abord les quatre arts qu\u2019on appelle \u201carts plastiques\u201d de nos jours : architecture, sculpture, peinture et gravure. Plus tard, la musique et les arts de la sc\xe8ne (th\xe9\xe2tre et danse) entreront dans la classification comme 5\xe8me et 6\xe8me arts. Puis arrive le cin\xe9ma, le septi\xe8me art, au d\xe9but du 20\xe8me si\xe8cle ; et enfin la photographie (avec la t\xe9l\xe9vision et la radio) comme 8\xe8me art, et derni\xe8rement la bande-dessin\xe9e comme 9\xe8me art."}),"\n",(0,i.jsx)(t.h2,{id:"trois-\xe9l\xe9ments-classiques-de-distinction-entre-ce-qui-est-de-lart-et-ce-qui-nen-est-pas",children:"Trois \xe9l\xe9ments classiques de distinction entre ce qui est de l\u2019art et ce qui n\u2019en est pas"}),"\n",(0,i.jsx)(t.p,{children:"L\u2019\u0153uvre d\u2019art se distingue par sa finalit\xe9, qui n\u2019est pas la m\xeame que celle d\u2019un outil : elle n\u2019a pas de vocation utilitaire. L\u2019objet de l\u2019artisan ou de l\u2019industrie n\u2019a pas de valeur en lui-m\xeame : il sert \xe0 quelque chose, il est outil qui a une fonction. L\u2019\u0153uvre d\u2019art ne peut pas servir \xe0 quelque chose : on ne la manipule pas, on la contemple.\nAnecdote de Van Gogh : en 1889, hospitalis\xe9, il peint le portrait de son docteur (Rey) et lui offre. Le docteur trouve ce portrait invraisemblable et ridicule, le range pendant plus de dix ans dans un poulailler afin de boucher un trou, puis l\u2019oublie dans un grenier. Il sera ensuite retrouv\xe9 et vendu. En plus d\u2019interroger sur le statut de l\u2019artiste, qui n\u2019est pas toujours reconnu de son vivant, ce fait pose le probl\xe8me de notre rapport aux \u0153uvres d\u2019art : les utiliser, c\u2019est en nier leur vocation artistique. Si on met de la musique pour s\xe9duire quelqu\u2019un, ou un tableau pour d\xe9corer son int\xe9rieur, alors la musique et la peinture ne sont plus que des outils : on ne les appr\xe9cie pas pour ce qu\u2019ils sont, mais pour ce \xe0 quoi ils servent. Ils ne sont plus que des moyens, et pas des fins en soi.\nProbl\xe8me : l\u2019art peut avoir une fonction utilitaire : jusqu\u2019au moyen-\xe2ge il est li\xe9 au sacr\xe9, \xe0 la r\xe9v\xe9lation religieuse ; il peut aussi transmettre des messages politiques, moraux, sociaux. L\u2019art est-il donc r\xe9ellement d\xe9tach\xe9 de toute utilit\xe9 ?"})]})}function c(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}}}]);